// A special identifier within the store generated by createStore
export const __REGENERATIVE_SYSTEM_KEY__ = Symbol("regenerativeSystemKey");

// The key of useStore
export const __USE_STORE_KEY__ = Symbol("useStoreKey");

// The key of useSignal
export const __USE_SIGNAL_STORE_KEY__ = Symbol("useSignalStoreKey");

// The key of viewer suffix key
export const __VIEWER_SUFFIX_KEY__ = "_ViewerSuffixKey";

// The key of signal suffix key
export const __SIGNAL_SUFFIX_KEY__ = "_SignalSuffixKey";

// string constants for signal internal deep stitching attributes
export const __DEEP_SPLICE_KEY__ = "_$_¥_$_";

// Properties of proxies within signals that require special handling
export const signalSymbolPropsSet =
  new Set<symbol>()
    .add(Symbol.toPrimitive)
    .add(Symbol.toStringTag)
    .add(Symbol.iterator);

export const prototypeSpecialKeyFnSet =
  new Set<string>()
    .add("get")
    .add("set")
    .add("add")
    .add("has")
    .add("delete");
